## Subcommand: add
```
USAGE:
    cass pages key add [OPTIONS]

OPTIONS:
    --archive <DIR>         Path to site/ directory [required]
    --password <PASS>       Current password to authenticate [prompted if not provided]
    --new-password <PASS>   New password for the new slot [prompted if not provided]
    --recovery              Generate a recovery secret instead of password
    --label <TEXT>          Optional label for the slot (stored in encrypted metadata)
    --json                  Output in JSON format

EXAMPLES:
    # Add password for a teammate
    cass pages key add --archive ./site \
        --password "current" \
        --new-password "teammate-pass" \
        --label "alice"

    # Add recovery secret
    cass pages key add --archive ./site \
        --password "current" \
        --recovery \
        --label "backup-2025"

OUTPUT:
    ✓ Added key slot [3] (alice)

    The new password can now be used to unlock the archive.
    (For recovery secrets, the secret is printed once - save it securely!)
```

### Implementation
```rust
pub async fn key_add(
    archive_dir: &Path,
    current_password: &str,
    new_secret: KeySlotSecret,
    label: Option<String>,
) -> Result<AddKeyResult, KeyError> {
    // 1. Load config.json
    let config_path = archive_dir.join("config.json");
    let mut config: Config = serde_json::from_str(&fs::read_to_string(&config_path)?)?;

    // 2. Derive KEK from current password and unwrap DEK
    let dek = unwrap_dek_from_any_slot(&config, current_password)?;

    // 3. Generate new key slot
    let new_slot = match new_secret {
        KeySlotSecret::Password(pw) => {
            create_password_slot(&pw, &dek, &config.export_id, config.key_slots.len() as u32)?
        }
        KeySlotSecret::Recovery => {
            let secret = generate_recovery_secret();
            let slot = create_recovery_slot(&secret, &dek, &config.export_id, config.key_slots.len() as u32)?;
            return Ok(AddKeyResult::RecoverySlot { slot, secret });
        }
    };

    // 4. Add slot to config
    config.key_slots.push(new_slot);

    // 5. Write updated config.json
    fs::write(&config_path, serde_json::to_string_pretty(&config)?)?;

    // 6. Update integrity.json if present
    update_integrity_hash(&archive_dir, "config.json")?;

    Ok(AddKeyResult::PasswordSlot { slot_id: config.key_slots.len() - 1 })
}

fn create_password_slot(
    password: &str,
    dek: &[u8; 32],
    export_id: &[u8; 16],
    slot_id: u32,
) -> Result<KeySlot, KeyError> {
    let mut salt = [0u8; 16];
    let mut nonce = [0u8; 12];
    rand::thread_rng().fill_bytes(&mut salt);
    rand::thread_rng().fill_bytes(&mut nonce);

    // Derive KEK via Argon2id
    let kek = derive_kek_argon2id(password.as_bytes(), &salt, &DEFAULT_KDF_PARAMS)?;

    // Wrap DEK
    let cipher = Aes256Gcm::new(Key::<Aes256Gcm>::from_slice(&kek));
    let aad = build_slot_aad(export_id, slot_id);
    let wrapped_dek = cipher.encrypt(
        Nonce::from_slice(&nonce),
        Payload { msg: dek, aad: &aad }
    )?;

    Ok(KeySlot {
        id: slot_id,
        slot_type: "password".to_string(),
        kdf: "argon2id".to_string(),
        kdf_params: Some(DEFAULT_KDF_PARAMS.clone()),
        salt: salt.to_vec(),
        nonce: nonce.to_vec(),
        wrapped_dek,
    })
}
```

## Subcommand: revoke
```
USAGE:
    cass pages key revoke [OPTIONS]

OPTIONS:
    --archive <DIR>     Path to site/ directory [required]
    --password <PASS>   Current password to authenticate [prompted]
    --slot-id <ID>      ID of slot to revoke [required]
    --json              Output in JSON format

SAFETY:
    - Cannot revoke the last remaining slot
    - Must authenticate with a DIFFERENT slot than the one being revoked
    - Prompts for confirmation

EXAMPLES:
    cass pages key revoke --archive ./site --slot-id 2

OUTPUT:
    ⚠️  This will permanently remove key slot [2] (alice).
    Anyone using that password will no longer be able to unlock the archive.

    ? Proceed? (y/N) y

    ✓ Revoked key slot [2]

    Remaining slots: 2
```

### Implementation
```rust
pub async fn key_revoke(
    archive_dir: &Path,
    current_password: &str,
    slot_id_to_revoke: u32,
) -> Result<RevokeResult, KeyError> {
    let config_path = archive_dir.join("config.json");
    let mut config: Config = serde_json::from_str(&fs::read_to_string(&config_path)?)?;

    // Safety: Cannot revoke last slot
    if config.key_slots.len() <= 1 {
        return Err(KeyError::CannotRevokeLastSlot);
    }

    // Safety: Must authenticate with different slot
    let (auth_slot_id, dek) = unwrap_dek_with_slot_id(&config, current_password)?;
    if auth_slot_id == slot_id_to_revoke {
        return Err(KeyError::CannotRevokeAuthenticatingSlot);
    }

    // Remove the slot
    config.key_slots.retain(|s| s.id != slot_id_to_revoke);

    // Re-number remaining slots (IDs are positional)
    for (i, slot) in config.key_slots.iter_mut().enumerate() {
        slot.id = i as u32;
    }

    // Write updated config
    fs::write(&config_path, serde_json::to_string_pretty(&config)?)?;
    update_integrity_hash(&archive_dir, "config.json")?;

    Ok(RevokeResult {
        revoked_slot_id: slot_id_to_revoke,
        remaining_slots: config.key_slots.len(),
    })
}
```

## Subcommand: rotate
```
USAGE:
    cass pages key rotate [OPTIONS]

DESCRIPTION:
    Full key rotation: generates a new DEK and re-encrypts the entire payload.
    Use this when the DEK itself may be compromised (not just a password).

OPTIONS:
    --archive <DIR>         Path to site/ directory [required]
    --old-password <PASS>   Current password to decrypt [prompted]
    --new-password <PASS>   New password for rotated archive [prompted]
    --keep-recovery         Also create a recovery slot

EXAMPLES:
    cass pages key rotate --archive ./site \
        --old-password "compromised" \
        --new-password "fresh-secure-pass"

OUTPUT:
    ⚠️  Full key rotation will:
      • Decrypt all payload chunks
      • Generate a new Data Encryption Key (DEK)
      • Re-encrypt all payload chunks
      • Replace all existing key slots

    This operation may take several minutes for large archives.

    ? Proceed? (y/N) y

    Decrypting payload... ████████████████████ 100%
    Re-encrypting payload... ████████████████████ 100%

    ✓ Key rotation complete

    New DEK created at: 2025-01-07T10:00:00Z
    Key slots: 1 (new password)
```

### Implementation
```rust
pub async fn key_rotate(
    archive_dir: &Path,
    old_password: &str,
    new_password: &str,
    keep_recovery: bool,
    progress: impl FnMut(f32),
) -> Result<RotateResult, KeyError> {
    let config_path = archive_dir.join("config.json");
    let config: Config = serde_json::from_str(&fs::read_to_string(&config_path)?)?;

    // 1. Decrypt payload with old password
    let old_dek = unwrap_dek_from_any_slot(&config, old_password)?;
    let plaintext = decrypt_all_chunks(&archive_dir, &old_dek, &config, |p| progress(p * 0.5))?;

    // 2. Generate new DEK and export_id
    let mut new_dek = [0u8; 32];
    let mut new_export_id = [0u8; 16];
    let mut new_base_nonce = [0u8; 12];
    rand::thread_rng().fill_bytes(&mut new_dek);
    rand::thread_rng().fill_bytes(&mut new_export_id);
    rand::thread_rng().fill_bytes(&mut new_base_nonce);

    // 3. Re-encrypt payload with new DEK
    let chunk_count = encrypt_all_chunks(
        &plaintext,
        &new_dek,
        &new_export_id,
        &new_base_nonce,
        config.payload.chunk_size as usize,
        &archive_dir.join("payload"),
        |p| progress(0.5 + p * 0.5),
    )?;

    // 4. Create new key slots
    let mut new_slots = vec![
        create_password_slot(new_password, &new_dek, &new_export_id, 0)?
    ];

    if keep_recovery {
        let secret = generate_recovery_secret();
        new_slots.push(create_recovery_slot(&secret, &new_dek, &new_export_id, 1)?);
        // Return secret to caller for display
    }

    // 5. Write new config
    let new_config = Config {
        version: config.version,
        export_id: base64_encode(&new_export_id),
        base_nonce: base64_encode(&new_base_nonce),
        compression: config.compression,
        kdf_defaults: config.kdf_defaults,
        payload: PayloadConfig {
            chunk_size: config.payload.chunk_size,
            chunk_count,
            files: (0..chunk_count)
                .map(|i| format!("payload/chunk-{:05}.bin", i))
                .collect(),
        },
        key_slots: new_slots,
        exported_at: Utc::now().to_rfc3339(),
        cass_version: env!("CARGO_PKG_VERSION").to_string(),
    };

    fs::write(&config_path, serde_json::to_string_pretty(&new_config)?)?;

    // 6. Regenerate integrity.json
    regenerate_integrity_manifest(&archive_dir)?;

    // 7. Zeroize old DEK
    old_dek.zeroize();
    new_dek.zeroize();

    Ok(RotateResult {
        new_dek_created_at: Utc::now(),
        slot_count: new_config.key_slots.len(),
    })
}
```

