fn test_discovery_high_parallelism() {
    // Force Rayon to use many threads
    let pool = rayon::ThreadPoolBuilder::new()
        .num_threads(16)
        .build()
        .unwrap();

    pool.install(|| {
        for _ in 0..100 {
            let paths = create_test_paths(10_000);
            let result = discover_agents_optimized(&paths);

            // Verify no data corruption from race conditions
            let total: usize = result.values().map(|v| v.len()).sum();
            // Should discover expected count (paths with valid agents)
            assert!(total > 0);
        }
    });
