fn discover_agents_optimized(paths: &[PathBuf]) -> HashMap<AgentType, Vec<PathBuf>> {
    let start = std::time::Instant::now();
    tracing::debug!(file_count = paths.len(), "Starting agent discovery");

    let result = paths.par_iter()
        .fold(HashMap::new, |mut acc, path| {
            if let Some(agent_type) = detect_agent(path) {
                acc.entry(agent_type)
                    .or_insert_with(Vec::new)
                    .push(path.clone());
            }
            acc
        })
        .reduce(HashMap::new, |mut a, b| {
            for (agent, mut paths) in b {
                a.entry(agent)
                    .or_insert_with(Vec::new)
                    .append(&mut paths);
            }
            a
        });

    tracing::info!(
        elapsed_ms = start.elapsed().as_millis() as u64,
        agents_found = result.len(),
        total_files = result.values().map(|v| v.len()).sum::<usize>(),
        "Agent discovery complete"
    );

    if tracing::enabled!(tracing::Level::DEBUG) {
        for (agent, paths) in &result {
            tracing::debug!(agent = ?agent, count = paths.len(), "Discovered agent");
        }
    }

    result
}
